    irq_vector => C_0_16,
    code_addr => w50,
    data_rd_addr => w51,
    data_wr_en => w52,
    data_wr_addr => w53,
    data_wr_data => w54
  );
  w44 <= rom_44(to_integer(w50)) when not is_x(w50) else (others => '0');
  w56 <= w50 + C_1_16;
  w46 <= rom_46(to_integer(w56)) when not is_x(w56) else (others => '0');
  w57 <= resize(w53, 32);
  w58 <= resize(w51, 32);
  gpio_port <= w40;
  gpio_ddr <= w41;
end architecture rtl;

